namespace sv_2850253560a3470bb8c0d0d2193d4475.Services;

public class WizardState
{
    // Step 1: Personal Info
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";

    // Step 2: Experience
    public List<JobEntry> JobHistory { get; set; } = new();

    // Step 3: References
    public List<Reference> References { get; set; } = new();

    // Progress tracking
    public HashSet<int> CompletedSteps { get; set; } = new();
    public int CurrentStep { get; set; } = 1;
}

public class JobEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Duration { get; set; } = "";
}

public class Reference
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Phone { get; set; } = "";
}

using System.Collections.Concurrent;

namespace sv_2850253560a3470bb8c0d0d2193d4475.Services;

/// <summary>
/// Singleton service that stores wizard state keyed by session ID.
/// Both static SSR (layout) and interactive pages use this same store.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardState> _states = new();

    public WizardState GetOrCreate(string sessionId)
    {
        return _states.GetOrAdd(sessionId, _ => new WizardState());
    }

    public void Remove(string sessionId)
    {
        _states.TryRemove(sessionId, out _);
    }
}

