                            var stepClass = state.CompletedSteps.Contains(i) ? "completed"
                                          : i == currentStep ? "active"
                                          : "";
                            <span class="badge @(stepClass == "completed" ? "bg-success" : stepClass == "active" ? "bg-primary" : "bg-secondary")">
                                Step @i
                            </span>
