@page "/apply/personal-info"
@rendermode InteractiveServer
@inject sv_2850253560a3470bb8c0d0d2193d4475.Services.WizardStateStore WizardStore
@inject IHttpContextAccessor HttpContextAccessor
@inject PersistentComponentState PersistentState
@inject NavigationManager Nav

<h3>Step 1: Personal Information</h3>

<EditForm Model="state" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Name</label>
        <InputText class="form-control" @bind-Value="state.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="state.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    private WizardState state = new();
    private string _sessionId = "";
    private PersistingComponentStateSubscription _subscription;

    protected override void OnInitialized()
    {
        _subscription = PersistentState.RegisterOnPersisting(PersistState);

        if (PersistentState.TryTakeFromJson<string>("SessionId", out var restored))
        {
            _sessionId = restored!;
        }
        else
        {
            // During prerender (static SSR), HttpContext is available
            _sessionId = HttpContextAccessor.HttpContext?.Session.Id ?? "";
        }

        state = WizardStore.GetOrCreate(_sessionId);
    }

    private Task PersistState()
    {
        PersistentState.PersistAsJson("SessionId", _sessionId);
        return Task.CompletedTask;
    }

    private void Next()
    {
        state.CompletedSteps.Add(1);
        Nav.NavigateTo("/apply/experience");
    }

    public void Dispose() => _subscription.Dispose();
}

@page "/apply/experience"
@rendermode InteractiveServer
@inject sv_2850253560a3470bb8c0d0d2193d4475.Services.WizardStateStore WizardStore
@inject IHttpContextAccessor HttpContextAccessor
@inject PersistentComponentState PersistentState
@inject NavigationManager Nav

<h3>Step 2: Experience</h3>

@foreach (var job in state.JobHistory)
{
    <div class="card mb-2 p-2">
        <strong>@job.Company</strong> — @job.Title (@job.Duration)
    </div>
}

<div class="border p-3 mb-3">
    <h5>Add Job</h5>
    <div class="mb-2">
        <InputText class="form-control" placeholder="Company" @bind-Value="newJob.Company" />
    </div>
    <div class="mb-2">
        <InputText class="form-control" placeholder="Title" @bind-Value="newJob.Title" />
    </div>
    <div class="mb-2">
        <InputText class="form-control" placeholder="Duration" @bind-Value="newJob.Duration" />
    </div>
    <button class="btn btn-outline-primary" @onclick="AddJob">Add</button>
</div>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private WizardState state = new();
    private JobEntry newJob = new();
    private string _sessionId = "";
    private PersistingComponentStateSubscription _subscription;

    protected override void OnInitialized()
    {
        _subscription = PersistentState.RegisterOnPersisting(PersistState);

        if (PersistentState.TryTakeFromJson<string>("SessionId", out var restored))
            _sessionId = restored!;
        else
            _sessionId = HttpContextAccessor.HttpContext?.Session.Id ?? "";

        state = WizardStore.GetOrCreate(_sessionId);
    }

    private Task PersistState()
    {
        PersistentState.PersistAsJson("SessionId", _sessionId);
        return Task.CompletedTask;
    }

    private void AddJob()
    {
        state.JobHistory.Add(newJob);
        newJob = new();
    }

    private void Back() => Nav.NavigateTo("/apply/personal-info");

    private void Next()
    {
        state.CompletedSteps.Add(2);
        Nav.NavigateTo("/apply/references");
    }

    public void Dispose() => _subscription.Dispose();
}

