toolArgs.file_text:
@page "/apply/review"
@rendermode InteractiveServer
@inject sv_2850253560a3470bb8c0d0d2193d4475.Services.WizardStateStore WizardStore
@inject IHttpContextAccessor HttpContextAccessor
@inject PersistentComponentState PersistentState

<h3>Step 4: Review Your Application</h3>

<div class="card p-3 mb-3">
    <h5>Personal Info</h5>
    <p><strong>Name:</strong> @state.Name</p>
    <p><strong>Email:</strong> @state.Email</p>
</div>

<div class="card p-3 mb-3">
    <h5>Experience</h5>
    @if (state.JobHistory.Any())
    {
        @foreach (var job in state.JobHistory)
        {
            <p>@job.Company — @job.Title (@job.Duration)</p>
        }
    }
    else
    {
        <p class="text-muted">No entries</p>
    }
</div>

<div class="card p-3 mb-3">
    <h5>References</h5>
    @if (state.References.Any())
    {
        @foreach (var r in state.References)
        {
            <p>@r.Name — @r.Relationship (@r.Phone)</p>
        }
    }
    else
    {
        <p class="text-muted">No entries</p>
    }
</div>

<div class="d-flex gap-2">
    <a href="/apply/references" class="btn btn-secondary">← Back</a>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (submitted)
{
    <div class="alert alert-success mt-3">Application submitted!</div>
}

@code {
    private WizardState state = new();
    private string _sessionId = "";
    private bool submitted;
    private PersistingComponentStateSubscription _subscription;

    protected override void OnInitialized()
    {
        _subscription = PersistentState.RegisterOnPersisting(PersistState);

        if (PersistentState.TryTakeFromJson<string>("SessionId", out var restored))
            _sessionId = restored!;
        else
            _sessionId = HttpContextAccessor.HttpContext?.Session.Id ?? "";

        state = WizardStore.GetOrCreate(_sessionId);
    }

    private Task PersistState()
    {
        PersistentState.PersistAsJson("SessionId", _sessionId);
        return Task.CompletedTask;
    }

    private void Submit()
    {
        state.CompletedSteps.Add(4);
        submitted = true;
        // In production: persist to DB, then call WizardStore.Remove(_sessionId)
    }

    public void Dispose() => _subscription.Dispose();
}

